// And groups predicates with the AND operator between them.
func And(predicates ...predicate.OAuthRemoteConnection) predicate.OAuthRemoteConnection {
	return predicate.OAuthRemoteConnection(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.OAuthRemoteConnection) predicate.OAuthRemoteConnection {
	return predicate.OAuthRemoteConnection(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.OAuthRemoteConnection) predicate.OAuthRemoteConnection {
	return predicate.OAuthRemoteConnection(sql.NotPredicates(p))
}
